using UnityEngine;

/// <summary>
/// Runa de Gaia — concede <see cref="amount"/> ao saldo/total de Runas
/// (<c>PlayerProgress.GiveRunasDeGaia</c>) e regista "encontrada" na área
/// (<c>AreaProgress.runasFound</c> / <c>AreaData.totalRunas</c>) uma vez por
/// unidade concedida.
/// </summary>
public class RunaDeGaiaPickup : PickupBase
{
    [Header("Runa de Gaia")]
    [Tooltip("Quantidade de Runas de Gaia concedidas (normalmente 1).")]
    [Min(1)] public int amount = 1;

    public override PickupType Type => PickupType.RunaDeGaia;

    protected override void GrantReward()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        progress.GiveRunasDeGaia(amount);

        if (area != null)
            for (int i = 0; i < amount; i++) progress.AddRunaFound(area);
    }
}
